// 目利きAgentが吐き出したテキストを解凍する
const rawData = $input.item.json.output;
if (!rawData || typeof rawData !== 'string' || rawData.trim() === '') {
  throw new Error('目利きAgentの出力が空です。Geminiがタイムアウトまたは空応答を返しました。');
}

// コードフェンス除去
let cleaned = rawData.replace(/```json|```/g, '').trim();

let cleanData;
try {
  // 戦略1: そのままパース
  cleanData = JSON.parse(cleaned);
} catch (e1) {
  try {
    // 戦略2: JSON文字列内の制御文字をエスケープしてから再パース
    const fixed = cleaned.replace(
      /("(?:[^"\\]|\\.)*")|([^"]+)/g,
      (match, str, nonStr) => {
        if (str) return str; // 文字列内はそのまま
        return nonStr.replace(/\n/g, '').replace(/\r/g, ''); // 文字列外の改行除去
      }
    );
    cleanData = JSON.parse(fixed);
  } catch (e2) {
    try {
      // 戦略3: 文字列全体の制御文字を除去してパース
      const sanitized = cleaned
        .replace(/\\n/g, '__NEWLINE__')  // 正規のエスケープは保護
        .replace(/[\n\r]/g, ' ')         // 裸の改行を除去
        .replace(/__NEWLINE__/g, '\\n'); // 復元
      cleanData = JSON.parse(sanitized);
    } catch (e3) {
      // 戦略4: オブジェクトを個別に抽出
      const matches = cleaned.match(/\{[^]*?\}(?=\s*[,\]]|\s*$)/g) || [];
      cleanData = matches.map(m => {
        try { return JSON.parse(m); } catch { return null; }
      }).filter(Boolean);
      if (cleanData.length === 0) {

      // 戦略5: 途中切れJSONの修復
      let repaired = cleaned;
      // 開き括弧・文字列状態を追跡して強制クローズ
      let inStr = false;
      let escapeNext = false;
      let depth = 0;
      for (let i = 0; i < repaired.length; i++) {
        const c = repaired[i];
        if (escapeNext) { escapeNext = false; continue; }
        if (c === '\\\\') { escapeNext = true; continue; }
        if (c === '"') { inStr = !inStr; continue; }
        if (inStr) continue;
        if (c === '{' || c === '[') depth++;
        if (c === '}' || c === ']') depth--;
      }
      if (inStr) repaired += '"';      // 開きっぱなしの文字列を閉じる
      while (depth > 0) {
        repaired += '}';
        depth--;
      }
      // 末尾のカンマ除去 + 配列クローズ
      repaired = repaired.replace(/,\s*$/, '') + ']';
      try {
        cleanData = JSON.parse(repaired.startsWith('[') ? repaired : '[' + repaired);
      } catch (e5) {
        throw new Error('JSON解析に全戦略が失敗: ' + e3.message);
      }

      }
    }
  }
}

// URLからメディア名を抽出する関数
function extractMediaName(url) {
  try {
    const hostname = new URL(url).hostname.replace('www.', '');
    const mediaMap = {
      'techcrunch.com': 'TechCrunch',
      'gizmodo.com': 'Gizmodo',
      'gizmodo.jp': 'ギズモード・ジャパン',
      'engadget.com': 'Engadget',
      'theverge.com': 'The Verge',
      'wired.com': 'WIRED',
      'itmedia.co.jp': 'ITmedia',
      'gigazine.net': 'GIGAZINE',
      'inoreader.com': 'Inoreader',
      'reuters.com': 'Reuters',
      'bloomberg.com': 'Bloomberg',
      'nikkei.com': '日本経済新聞',
    };
    return mediaMap[hostname] || hostname.split('.')[0];
  } catch (e) {
    return 'Unknown';
  }
}

// 5件のニュースを、元のURLやタイトルを維持したままバラバラにして出力する
return cleanData.map(item => {
  const url = $input.item.json.url || item.url;
  return {
    json: {
      ...item,
      url: url,
      original_title: $input.item.json.title,
      mediaName: extractMediaName(url)
    }
  };
});

// ============================================================
// 画像プロンプト抽出｜Code in JavaScript2（2026-03-19 新MOEBIUS構造版）
// 入力元: ニュース画像プロンプト生成エージェント（chainLlm）
// 取得: image_prompt（タイトル画像用）+ news_image_prompts（ニュース8本用）
// ============================================================

// ============ タイトル画像用 新構造 ============
const MOEBIUS_STYLE = 'no signature no text no numbers, Moebius bande dessinee panel, strong confident black ink outlines ligne claire, rich ink crosshatching and stippling throughout, transparent watercolor washes over ink with visible uneven brushwork, color variation within zones human imperfection';

// タイトル画像：Type D（夜明け空）+ 明系照明
const TITLE_COMPOSITION = 'vast luminous sky filling upper three-quarters of composition, dramatic dawn or golden hour light breaking at horizon, small solitary figure on elevated ground facing the light, atmospheric watercolor haze and light scattering';

const TITLE_LIGHTING = 'bright morning golden hour light luminous clear atmosphere warm gold and cream radiant quality';

// タイトル用フォールバックシーン
const TITLE_FALLBACK = 'single researcher silhouette standing at hilltop facing vast luminous horizon where digital city meets dawn sky, warm amber and gold light flooding the scene, small birds visible in distance';
// ============ タイトル画像用 新構造ここまで ============

return items.map(item => {
  let rawOutput = item.json.text || item.json.output || "";

  let cleanOutput = rawOutput.replace(/```json[\s\S]*?```/g, (m) => m.replace(/```json\n?/,'').replace(/\n?```/,'')).trim();
  cleanOutput = cleanOutput.replace(/```json|```/g, "").trim();

  let data;
  try {
    data = JSON.parse(cleanOutput || "{}");
  } catch (e) {
    try {
      const sanitized = cleanOutput.replace(/\\n/g,'__NL__').replace(/[\n\r]/g,' ').replace(/__NL__/g,'\\n');
      data = JSON.parse(sanitized || "{}");
    } catch (e2) {
      data = { image_prompt: "", news_image_prompts: [] };
    }
  }

  // タイトル画像: LLMが生成したSCENE部分を新構造で構築
  const titleScene = data.image_prompt || "";
  const scene = (titleScene && titleScene.length >= 20) ? titleScene : TITLE_FALLBACK;
  const finalPrompt = `${MOEBIUS_STYLE}, ${TITLE_COMPOSITION}, ${TITLE_LIGHTING}, ${scene}, layered ink and watercolor aesthetic, analog hand-made quality warmth`;

  // ニュース8枚: LLMが生成したSCENE配列をそのまま渡す（連結はニュース画像一括生成|Codeで行う）
  const newsPrompts = data.news_image_prompts || [];

  return {
    json: {
      ...item.json,
      image_prompt: finalPrompt,
      news_image_prompts: newsPrompts
    }
  };
});

