// ===== ファクトチェック済み出力｜Code =====
// FC成功時: Perplexity Sonarの修正済みJSONを使用
// FC失敗時: 日刊コラム執筆エージェントの元outputにフォールバック

const response = $input.item.json;

// STEP1: Perplexity FC の出力を取得・クリーニング
const rawFC = (response.choices?.[0]?.message?.content || '')
  .replace(/```json\n?/g, '')
  .replace(/\n?```$/g, '')
  .replace(/\n?```/g, '')
  .trim();

// STEP2: FC出力が有効なJSONかチェック
let checkedContent = '';
let usedFallback = false;

if (rawFC.length > 100) {
  try {
    JSON.parse(rawFC);
    // パース成功 → FCの出力をそのまま使う
    checkedContent = rawFC;
  } catch (e) {
    // パース失敗 → フォールバック
    usedFallback = true;
  }
} else {
  // 出力が短すぎる（途中切れの可能性）→ フォールバック
  usedFallback = true;
}

// STEP3: フォールバック処理
if (usedFallback) {
  // 日刊コラム執筆エージェントの元outputを使う
  const originalOutput = $node["日刊コラム執筆エージェント"].json.text || '';
  const cleanOriginal = originalOutput
    .replace(/```json\n?/g, '')
    .replace(/\n?```$/g, '')
    .replace(/\n?```/g, '')
    .trim();
  checkedContent = cleanOriginal;
}

return [{ json: { output: checkedContent, used_fallback: usedFallback } }];

const raw = $input.first().json;
const xmlText = typeof raw === 'string' ? raw : (raw.body || raw.data || JSON.stringify(raw));

// HTML entities decode
const decodeHtml = (str) => str
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&').replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'").replace(/&apos;/g, "'");

// タグ除去
const stripTags = (str) => str.replace(/<[^>]+>/g, '').trim();

const getTag = (xml, tag) => {
  const m = xml.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
  if (!m) return '';
  return decodeHtml(m[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1')).trim();
};

const itemMatches = [...xmlText.matchAll(/<item>([\s\S]*?)<\/item>/g)];
if (itemMatches.length === 0) {
  throw new Error('RSSアイテムが0件: ' + xmlText.substring(0, 200));
}

const items = itemMatches.map(match => {
  const item = match[1];
  const title = stripTags(getTag(item, 'title'));
  const rawDesc = getTag(item, 'description');

  // descriptionのHTMLから実URLを抽出
  const decodedDesc = rawDesc;
  const actualUrlMatch = decodedDesc.match(/href=["'](https?:\/\/[^"'\s>]+)["']/);
  const actualUrl = actualUrlMatch ? actualUrlMatch[1] : '';

  // Google Newsリダイレクト以外のURLを優先
  const googleNewsLink = (item.match(/<link>([^<]+)<\/link>/) || [])[1] || '';
  const finalLink = actualUrl && !actualUrl.includes('news.google.com/rss') ? actualUrl : googleNewsLink;

  // contentはdescriptionのリンクテキスト or title
  const descText = stripTags(decodedDesc);
  const content = descText.length > 20 ? descText : title;

  const pubDate = getTag(item, 'pubDate');
  let dateStr = new Date().toISOString().split('T')[0];
  if (pubDate) {
    try { dateStr = new Date(pubDate).toISOString().split('T')[0]; } catch(e) {}
  }

  const source = stripTags(getTag(item, 'source')) || 'Google News';

  return { title, content, finalLink, dateStr, source };
}).filter(i => i.title.length > 5);

// 最大25件（情報選別Agentに適切な量）
const limited = items.slice(0, 25);

return limited.map(i => ({
  json: {
    title: i.title,
    content: i.content,
    contentSnippet: i.content,
    link: i.finalLink,
    url: i.finalLink,
    original_pubDate: i.dateStr,
    Source: i.source,
  }
}));

// ファクトチェック済み出力|Code の元JSONを取得
const originalOutputStr = $node["ファクトチェック済み出力｜Code"].json.output
  .replace(/```json\n?/g, '').replace(/\n?```$/g, '').replace(/\n?```/g, '').trim();

let originalOutput;
try {
  originalOutput = JSON.parse(originalOutputStr);
} catch(e) {
  const introMatches = [...originalOutputStr.matchAll(/"intro_text"\s*:\s*"((?:[^"\\]|\\.)*)"/gs)];
  const titleMatches = [...originalOutputStr.matchAll(/"main_title"\s*:\s*"((?:[^"\\]|\\.)*)"/g)];
  originalOutput = {
    main_title: titleMatches.length > 0 ? titleMatches[0][1] : '',
    intro_text: introMatches.length > 0 ? introMatches[0][1] : '',
    column_text: ''
  };
}

const rewrittenText = $json.text || $json.output;
if (rewrittenText && rewrittenText.length > 100) {
  originalOutput.column_text = rewrittenText;
}

// news_image_prompts は ニュース画像一括生成|Code の input[1] から供給される
// ここでは column_text を含む output のみ出力する
// （news_image_prompts はこのノードでは設定しない）

// Notion children blocks を事前に構築
const text = originalOutput.column_text || '';
const chunkSize = 1990;
const chunks = [];
for (let i = 0; i < text.length; i += chunkSize) {
  chunks.push({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: text.substring(i, i + chunkSize) } }]
    }
  });
}
if (chunks.length === 0) {
  chunks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: '（本文なし）' } }] } });
}


// タイトル生成専用ノードの出力でmain_titleを上書き
const newTitle = $('タイトル生成専用｜AI Agent').first()?.json?.text?.trim()
  || $('タイトル生成専用｜AI Agent').first()?.json?.output?.trim();
if (newTitle && newTitle.length > 5 && newTitle.length < 100) {
  originalOutput.main_title = newTitle;
}

return [{ json: { output: JSON.stringify(originalOutput), notion_children: chunks } }];

// column_text抽出｜前処理Code
// 入力元: ファクトチェック済み出力｜Code ($json.output)
// 役割: column_text を取り出して 編集長の眼+リライター に渡す

const outputStr = $json.output || $json.text || '';
const clean = outputStr
  .replace(/```json\n?/g, '')
  .replace(/\n?```$/g, '')
  .replace(/\n?```/g, '')
  .trim();

let columnText = '';
try {
  const parsed = JSON.parse(clean);
  columnText = parsed.column_text || '';
} catch(e) {
  // JSONパース失敗: テキスト全体をフォールバックとして使用
  columnText = clean.length > 50 ? clean : '';
}

// columnTextが空の場合は $json.text をそのまま使用
if (!columnText || columnText.trim().length < 50) {
  columnText = $json.text || $json.output || '（コラム本文の取得に失敗しました）';
}

return [{ json: { column_text: columnText } }];

// blog-posts-data.json の現在の内容をBase64デコード
const fetchResult = $('blog-posts-data.json取得｜HTTP Request').first().json;
const currentJson = Buffer.from(fetchResult.content, 'base64').toString('utf-8');
const currentSha = fetchResult.sha;
const existingPosts = JSON.parse(currentJson);

// ファクトチェック済み出力から新記事データを取得（ファイルパス引き継ぎノードから参照）
const rawOutput = $('ファイルパス引き継ぎ｜Code').first().json.fact_checked_raw;
const cleaned = rawOutput.replace(/```json\n?/g, '').replace(/\n?```$/g, '').trim();
const articleData = JSON.parse(cleaned);

// Create a file ノードから slug を取得（ファイルパスから抽出）
const filePath = $('ファイルパス引き継ぎ｜Code').first().json.file_path || '';
const slugMatch = filePath.match(/src\/content\/blog\/(.+)\.md$/);
const slug = slugMatch ? slugMatch[1] : '';

// Cloudinary URL (Upload ノードから)
const imageUrl = $('ファイルパス引き継ぎ｜Code').first().json.secure_url || '';

// column_text を content 配列に分割
const columnText = articleData.column_text || '';

// セクションを分割（## または ### で始まる行をセクション区切りとする）
const sections = [];
const lines = columnText.split('\n');
let currentSection = '';
let currentText = '';

for (const line of lines) {
  if (line.match(/^#{1,3}\s+/)) {
    // 前のセクションを保存
    if (currentText.trim()) {
      sections.push({
        section: currentSection,
        text: currentText.trim()
      });
    }
    currentSection = line.replace(/^#{1,3}\s+/, '').trim();
    currentText = '';
  } else {
    currentText += line + '\n';
  }
}
// 最後のセクションを保存
if (currentText.trim()) {
  sections.push({
    section: currentSection,
    text: currentText.trim()
  });
}

// sections が0件の場合はcolumn_text全体を1セクションとして扱う
const contentArray = sections.length > 0 ? sections : [
  { section: '', text: columnText }
];

// 日付フォーマット（YYYY-MM-DD HH:mm）
const now = new Date();
const dateStr = now.toISOString().replace('T', ' ').slice(0, 16);

// 新記事エントリ
const newPost = {
  slug: slug,
  title: articleData.main_title || '',
  lead: articleData.intro_text || '',
  date: dateStr,
  readTime: '1分',
  category: articleData.category || 'AI時代のキャリア',
  image: imageUrl,
  content: contentArray
};

// 既存データの先頭に追加（slugが既に存在する場合は追加しない）
const alreadyExists = existingPosts.some(p => p.slug === slug);
let updatedPosts;
if (alreadyExists) {
  updatedPosts = existingPosts;
} else {
  updatedPosts = [newPost, ...existingPosts];
}

const updatedJson = JSON.stringify(updatedPosts, null, 2);
const updatedBase64 = Buffer.from(updatedJson).toString('base64');

return [{
  json: {
    updatedBase64: updatedBase64,
    currentSha: currentSha,
    slug: slug,
    newPostTitle: newPost.title,
    alreadyExists: alreadyExists
  }
}];

// ニュース画像一括生成｜Code（2026-03-19 新MOEBIUS構造版）
// news_image_prompts中継|Code から受け取った8本のプロンプト（SCENEのみ）を
// 構図プール×照明システムと連結して個別アイテムに分割して出力する

// ============ 新MOEBIUS構造 ============
const MOEBIUS_STYLE = 'no signature no text no numbers, Moebius bande dessinee panel, strong confident black ink outlines ligne claire, rich ink crosshatching and stippling throughout, transparent watercolor washes over ink with visible uneven brushwork, color variation within zones human imperfection';

const COMPOSITION_POOL = {
  A: 'extremely tiny silhouette of single person barely visible in far distance, wide panoramic composition with human figure at only 2 percent of image height, overwhelming scale of environment versus humanity, tiny black kite bird high in sky',
  B: 'dramatic overhead bird eye view looking directly down from above, human figures visible at natural scale from aerial perspective, architectural or technological grid pattern below, aerial composition revealing hidden order and structure',
  C: 'extreme close-up of machine or technology surface detail filling entire frame, circuit board traces or mechanical gears or keyboard keys, single human hand or eye barely visible at frame edge, intimate tactile texture',
  D: 'vast luminous sky filling upper three-quarters of composition, dramatic dawn or golden hour light breaking at horizon, small solitary figure on elevated ground facing the light, atmospheric watercolor haze and light scattering',
  E: 'two or three human figures at natural human scale in conversation or focused collaboration, intimate interior or sheltered outdoor setting, faces partially visible showing concentration or wonder, warm inviting atmosphere',
  F: 'abstract geometric data network pattern filling entire frame, luminous glowing nodes and flowing lines of information connecting throughout, no human figures present, pure conceptual information architecture beauty',
  G: 'surreal humorous juxtaposition of ordinary human figure performing mundane task alongside enormous AI machine or robot, unexpected absurd scale contrast between tiny human domesticity and towering technological enormity, subtle ironic warmth, slightly askew off-kilter perspective'
};

const LIGHTING_POOL = {
  dark:   'night atmosphere deep shadows cool blue and teal dominant cold dramatic palette',
  mid:    'amber golden twilight warm ochre and sienna tones balanced dusk glow soft shadows',
  bright: 'bright morning golden hour light luminous clear atmosphere warm gold and cream radiant quality'
};

// 挿絵8枚の構図×照明割り当て（インデックス順）
const INSERT_PLAN = [
  { comp: 'B', light: 'dark'   },
  { comp: 'C', light: 'mid'    },
  { comp: 'D', light: 'bright' },
  { comp: 'E', light: 'mid'    },
  { comp: 'F', light: 'dark'   },
  { comp: 'A', light: 'mid'    },
  { comp: 'C', light: 'bright' },
  { comp: 'G', light: 'mid'    },
];
// ============ 新MOEBIUS構造ここまで ============

// デフォルトSCENEフォールバック（各ニュース用・構図タイプ対応版）
const FALLBACK_SCENES = [
  'vast automated warehouse floor seen from directly overhead, conveyor belts and robotic arms in precise geometric grid pattern, tiny worker figures visible at floor level',
  'extreme close-up of AI processor chip surface, microscopic circuit traces and gold contact points filling frame, human fingerprint impression barely visible at corner edge',
  'vast cloud-streaked dawn sky over digital city skyline, warm amber light breaking through morning mist, lone researcher silhouette on rooftop facing sunrise',
  'three figures in glass-walled meeting room, holographic data visualization floating between them, faces intent with focused concentration, city skyline visible outside window',
  'abstract glowing neural network filling entire frame, billions of luminous connection points pulsing with light, deep indigo fading to warm amber gradient, no human figures',
  'lone figure stands before vast glowing data network stretching to horizon, tiny human dwarfed by luminous digital infrastructure, dusk atmosphere amber glow on concrete landscape',
  'extreme close-up of surveillance camera lens rings reflecting distorted cityscape, concentric glass circles in morning light, human eye reflected at center of innermost lens',
  'ordinary office worker sitting at comically tiny desk typing on laptop, surrounded by towering server racks stretching to ceiling like skyscrapers, absurd scale contrast between human mundanity and machine enormity, warm amber ironic lighting'
];

function buildMoebiusPrompt(scenePart, fallbackScene, plan) {
  const scene = (scenePart && scenePart.trim().length > 20)
    ? scenePart.trim()
    : fallbackScene;
  const comp = COMPOSITION_POOL[plan.comp];
  const light = LIGHTING_POOL[plan.light];
  const rawPrompt = `${MOEBIUS_STYLE}, ${comp}, ${light}, ${scene}, layered ink and watercolor aesthetic, analog hand-made quality warmth`;
  return rawPrompt.replace(/"/g, "'");
}

const inputData = $input.first().json;

let prompts = inputData.news_image_prompts;
if (!Array.isArray(prompts)) {
  prompts = Object.values(prompts || {});
}

const parsedOutput   = inputData.parsed_output   || {};
const columnText     = inputData.column_text     || '';
const totalCount     = prompts.length;

if (prompts.length === 0) {
  const plan0 = INSERT_PLAN[0];
  const fallbackPrompt = buildMoebiusPrompt('', FALLBACK_SCENES[0], plan0);
  return [{ json: { prompt: fallbackPrompt, index: 0, total: 0, parsed_output: parsedOutput, column_text: columnText } }];
}

return prompts.map(function(scenePart, i) {
  const plan = INSERT_PLAN[i % INSERT_PLAN.length];
  const fallback = FALLBACK_SCENES[i % FALLBACK_SCENES.length];
