// ニュースベースtweet生成｜Code（2026-03-19 イーロン・マスク実装）
// column_textからニュースベースのtweetを生成する

// 前ノード（ファイルパス引き継ぎ｜Code）の出力を取得
const data = $input.first().json;
const columnText = data.column_text || '';
const introText = data.intro_text || '';

// tweet生成関数
function generateNewsTweet(columnText, introText) {
  // column_text から最初のニュース記事ブロックを抽出する
  // パターン: ### 【ニュース: タイトル（日付）】
  const newsBlockMatch = columnText.match(/###\s*【ニュース[:\s：]*([^【】]+?)(?:（[^）]*）)?】[\s\S]*?(?=###\s*【ニュース|##\s*【総括|$)/);

  let tweetText = '';

  if (newsBlockMatch) {
    const newsBlock = newsBlockMatch[0];

    // 事実概要（abstract_rewrite部分）を抽出
    // 「によると、」または最初の文章段落を取得
    const abstractMatch = newsBlock.match(/によると、([\s\S]*?)(?:\n\n|編集長の眼|\*\*編集長の眼)/);
    const factLine = abstractMatch ? ('によると、' + abstractMatch[1].trim()) : '';

    // ニュースタイトルを取得
    const titleMatch = newsBlock.match(/###\s*【ニュース[:\s：]*([^（【】\n]+)/);
    const newsTitle = titleMatch ? titleMatch[1].trim() : '';

    if (newsTitle && newsTitle.length > 5) {
      // タイトルを1行目に使用
      const firstLine = newsTitle.length <= 60 ? newsTitle : newsTitle.substring(0, 58) + '。';

      // 意味（これが意味すること）をfactLineから生成
      let meaningLine = '';
      if (factLine.length > 10) {
        // 「によると、」以降の最初の文（。まで）
        const firstSentenceMatch = factLine.match(/によると、([^。]+。)/);
        if (firstSentenceMatch) {
          const fact = firstSentenceMatch[1].trim();
          // 翻訳・解釈文として整形（40字以内）
          meaningLine = fact.length <= 45 ? fact : fact.substring(0, 43) + '…';
        }
      }

      // フォーマット組み立て
      if (meaningLine) {
        tweetText = `${firstLine}\n\nこれが意味すること：${meaningLine}\n\n詳細 →\n\n#AI活用 #AIサバイバル`;
      } else {
        tweetText = `${firstLine}\n\n詳細 →\n\n#AI活用 #AIサバイバル`;
      }
    }
  }

  // フォールバック: column_textから直接最初のニュースタイトルを抽出
  if (!tweetText || tweetText.length < 20) {
    const fallbackTitleMatch = columnText.match(/###\s*【ニュース[:\s：]*([^（【】\n]{5,70})/);
    if (fallbackTitleMatch) {
      const fb = fallbackTitleMatch[1].trim();
      tweetText = `${fb}\n\n詳細 →\n\n#AI活用 #AIサバイバル`;
    }
  }

  // 最終フォールバック: intro_textを加工（抽象文は禁止なので最低限の加工）
  if (!tweetText || tweetText.length < 20) {
    // intro_textから具体的な部分を探す（固有名詞・数字パターン）
    const specificMatch = introText.match(/[A-Z][a-zA-Z]{2,}|[0-9０-９]+[%％万億兆円ドル]|\d{4}年/);
    if (specificMatch) {
      tweetText = `${introText.substring(0, 100)}\n\n詳細 →\n\n#AI活用 #AIサバイバル`;
    } else {
      tweetText = `詳細 →\n\n#AI活用 #AIサバイバル`;
    }
  }

  // 130字制限（ハッシュタグ除く部分）
  const withoutHashtags = tweetText.replace(/\n\n#AI活用 #AIサバイバル$/, '');
  if (withoutHashtags.length > 130) {
    // 切り詰めて再組み立て
    const trimmed = withoutHashtags.substring(0, 127) + '…';
    tweetText = trimmed + '\n\n#AI活用 #AIサバイバル';
  }

  return tweetText;
}

const tweetText = generateNewsTweet(columnText, introText);

// 全フィールドを引き継ぎつつ tweet_text を追加
return [{
  json: {
    ...data,
    tweet_text: tweetText
  }
}];

// pioneer_block挿入｜Code（2026-03-19 修正版）
// 修正内容:
//   - pioneer_blockを「---」区切り（総括セクション境界）の「前」に挿入
//   - 結果: ニュース本文 → 開拓者事例 → (---) → 総括 の順序になる

const mainItem = $input.first().json;
let columnText = mainItem.column_text || '';

// pioneer_blockを取得
let pioneer_block = '';
let pioneer_url = '';
try {
  const pioneerData = $('開拓者事例整形｜Code').first().json;
  pioneer_block = pioneerData.pioneer_block || '';
  pioneer_url = pioneerData.pioneer_url || '';
} catch(e) {
  pioneer_block = '';
  pioneer_url = '';
}

// pioneer_blockをcolumn_textに挿入
// 挿入位置: 「---\n\n## 【総括」の直前（---区切りの前）
if (pioneer_block && columnText) {
  // パターン1: ---区切り行がある場合（--- の前に挿入）
  if (columnText.match(/---\s*\n.*##.*総括/s)) {
    columnText = columnText.replace(/(---\s*\n)(.*##.*総括)/s, (m, dash, rest) => {
      return pioneer_block + '\n' + dash + rest;
    });
  }
  // パターン2: ## 【総括 が直接ある場合
  else if (columnText.includes('## 【総括') || columnText.includes('## 総括')) {
    columnText = columnText.replace(/(?=---\n|## 【総括|## 総括)/, pioneer_block + '\n\n');
  }
  // パターン3: どちらもない場合は末尾に追加
  else {
    columnText = columnText + '\n\n' + pioneer_block;
  }
}

return [{
  json: {
    ...mainItem,
    column_text: columnText,
    pioneer_url: pioneer_url
  }
}];
